     1→import fs from 'fs';
     2→import path from 'path';
     3→import type { Newsletter } from '@/lib/newsletter-types';
     4→
     5→export type { Story, Section, Newsletter } from '@/lib/newsletter-types';
     6→export { CATEGORY_STYLES } from '@/lib/newsletter-types';
     7→
     8→const DATA_DIR = path.join(process.cwd(), 'data', 'newsletters');
     9→
    10→export function getAllNewsletterDates(): string[] {
    11→  try {
    12→    if (!fs.existsSync(DATA_DIR)) return [];
    13→    const files = fs.readdirSync(DATA_DIR);
    14→    return files
    15→      .filter((f) => f.endsWith('.json'))
    16→      .map((f) => f.replace('.json', ''))
    17→      .filter((d) => /^\d{4}-\d{2}-\d{2}$/.test(d))
    18→      .sort()
    19→      .reverse();
    20→  } catch {
    21→    return [];
    22→  }
    23→}
    24→
    25→export function getNewsletter(date: string): Newsletter | null {
    26→  try {
    27→    const filePath = path.join(DATA_DIR, `${date}.json`);
    28→    const content = fs.readFileSync(filePath, 'utf-8');
    29→    return JSON.parse(content) as Newsletter;
    30→  } catch {
    31→    return null;
    32→  }
    33→}
    34→
    35→export function getLatestNewsletter(): Newsletter | null {
    36→  const dates = getAllNewsletterDates();
    37→  if (dates.length === 0) return null;
    38→  return getNewsletter(dates[0]);
    39→}
    40→
    41→export function getRecentNewsletters(
    42→  n = 7,
    43→  excludeDate?: string
    44→): Pick<Newsletter, 'date' | 'title'>[] {
    45→  const dates = getAllNewsletterDates()
    46→    .filter((d) => d !== excludeDate)
    47→    .slice(0, n);
    48→  return dates.flatMap((date) => {
    49→    const nl = getNewsletter(date);
    50→    return nl ? [{ date: nl.date, title: nl.title }] : [];
    51→  });
    52→}
    53→
    54→export function formatDate(dateStr: string): string {
    55→  const [year, month, day] = dateStr.split('-').map(Number);
    56→  const date = new Date(year, month - 1, day);
    57→  return date.toLocaleDateString('en-US', {
    58→    weekday: 'long',
    59→    year: 'numeric',
    60→    month: 'long',
    61→    day: 'numeric',
    62→  });
    63→}
