     1→import { notFound } from 'next/navigation';
     2→import {
     3→  getNewsletter,
     4→  getAllNewsletterDates,
     5→  getRecentNewsletters,
     6→} from '@/lib/newsletter';
     7→import NewsletterView from '@/components/NewsletterView';
     8→
     9→export const revalidate = 86400;
    10→
    11→export async function generateStaticParams() {
    12→  const dates = getAllNewsletterDates();
    13→  return dates.map((date) => ({ date }));
    14→}
    15→
    16→export async function generateMetadata({
    17→  params,
    18→}: {
    19→  params: Promise<{ date: string }>;
    20→}) {
    21→  const { date } = await params;
    22→  const newsletter = getNewsletter(date);
    23→  if (!newsletter) return { title: 'Not Found — AI Daily Flash' };
    24→  return {
    25→    title: newsletter.title,
    26→    description: newsletter.subtitle,
    27→  };
    28→}
    29→
    30→export default async function DatePage({
    31→  params,
    32→}: {
    33→  params: Promise<{ date: string }>;
    34→}) {
    35→  const { date } = await params;
    36→
    37→  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) notFound();
    38→
    39→  const newsletter = getNewsletter(date);
    40→  if (!newsletter) notFound();
    41→
    42→  const allDates = getAllNewsletterDates();
    43→  // For dated pages, show adjacent issues — the one before and others nearby
    44→  const recentIssues = getRecentNewsletters(6, date);
    45→  // Ensure "previous issue" is the date immediately before this one
    46→  const currentIndex = allDates.indexOf(date);
    47→  const prevDate = allDates[currentIndex + 1] ?? null;
    48→  const orderedRecent = prevDate
    49→    ? [
    50→        ...recentIssues.filter((i) => i.date === prevDate),
    51→        ...recentIssues.filter((i) => i.date !== prevDate),
    52→      ]
    53→    : recentIssues;
    54→  return <NewsletterView newsletter={newsletter} recentIssues={orderedRecent} />;
    55→}
